class Solution {
public:
    int minimumLength(string s) {
        int n = s.length();
        int i = 0;
        while (i < n) {
            int j = i + 1;
            while (j < n && s[i] == s[j]) {
                j++;
            }
            int k = j;
            while (k < n && s[k] == s[j - 1]) {
                k++;
            }
            if (j > i + 1 && k > j) {
                s = s.substr(i + 1, k - i - 1);
                i = 0;
            } else {
                i++;
            }
        }
        return s.length();
    }
};
